void Screen2ViewBase::flexButtonCallbackHandler(const touchgfx::AbstractButtonContainer& src)
{
    if (&src == &flexButton1)
    {
        //Interaction1
        //When flexButton1 clicked change screen to Screen1
        //Go to Screen1 with screen transition towards East
        application().gotoScreen1ScreenWipeTransitionEast();
    
        //Interaction2
        //When Interaction1 completed call virtual function
        //Call ExitFromScreen2
        ExitFromScreen2();
    }
    if (&src == &fireButton)
    {
        //Interaction3
        //When fireButton clicked call virtual function
        //Call FireBullet
        FireBullet();
    }
    if (&src == &pauseButton)
    {
        //Interaction4
        //When pauseButton clicked call virtual function
        //Call TogglePause
        TogglePause();
    }
}

void Screen2ViewBase::buttonCallbackHandler(const touchgfx::AbstractButton& src)
{
    if (&src == &restartButton)
    {
        //Interaction5
        //When restartButton clicked call virtual function
        //Call RestartGame
        RestartGame();
    }
    if (&src == &continueButton)
    {
        //Interaction6
        //When continueButton clicked call virtual function
        //Call ContinueGame
        ContinueGame();
    }
}
